import React from 'react';
import { MapContainer, TileLayer, CircleMarker, Polyline, Tooltip } from 'react-leaflet';
import 'leaflet/dist/leaflet.css'; // This is required to make the map look correct!

const AttackMap = ({ history }) => {
  // Leaflet uses [Latitude, Longitude] coordinates
  const locations = {
    'Russia': [60.0, 100.0],
    'China': [35.0, 104.0],
    'USA': [38.0, -95.0],
    'Brazil': [-10.0, -50.0],
    'India': [20.0, 78.0] 
  };

  const targetCoords = locations['India'];
  const activeAttacks = history ? history.filter(threat => threat.attack_type !== 'Normal') : [];

  return (
    <div style={{ width: '100%', height: '100%', borderRadius: '8px', overflow: 'hidden', border: '1px solid #c0c4c8' }}>
      
      {/* MapContainer gives you the real, zoomable map interface */}
      <MapContainer 
        center={[30, 20]} // Centers the map roughly between India and Europe
        zoom={2}          // Starting zoom level
        minZoom={2}
        style={{ height: "100%", width: "100%", background: '#baddf9' }}
      >
        
        {/* This loads the beautiful, highly detailed, light-themed map tiles */}
        <TileLayer
          url="https://{s}.basemaps.cartocdn.com/rastertiles/voyager/{z}/{x}/{y}{r}.png"
          attribution='&copy; OpenStreetMap contributors'
        />

        {/* The Target Node (India) */}
        <CircleMarker 
          center={targetCoords} 
          radius={8} 
          pathOptions={{ color: '#1e3a8a', fillColor: '#2563eb', fillOpacity: 0.8 }}
        >
          <Tooltip permanent direction="bottom" offset={[0, 10]} opacity={0.9}>
            <strong style={{ color: '#1e3a8a' }}>SOC NODE (INDIA)</strong>
          </Tooltip>
        </CircleMarker>

        {/* Draw the Attacks */}
        {activeAttacks.map((threat, index) => {
          const originCoords = locations[threat.origin_country] || locations['Russia'];
          
          return (
            <React.Fragment key={index}>
              {/* Draw the dashed attack route */}
              <Polyline
                positions={[originCoords, targetCoords]}
                pathOptions={{ color: '#ef4444', weight: 2, dashArray: '5, 5' }}
              />
              
              {/* Draw the Attacker's origin point and IP */}
              <CircleMarker 
                center={originCoords} 
                radius={6} 
                pathOptions={{ color: '#b91c1c', fillColor: '#ef4444', fillOpacity: 0.8 }}
              >
                <Tooltip permanent direction="top" offset={[0, -10]} opacity={0.9}>
                  <span style={{ fontFamily: "monospace", color: "#b91c1c", fontWeight: "bold" }}>
                    {threat.source_ip}
                  </span>
                </Tooltip>
              </CircleMarker>
            </React.Fragment>
          );
        })}
        
      </MapContainer>
    </div>
  );
};

export default AttackMap;
